import React, { useContext } from "react";
import { CartContext } from "../context/CartContext";
import { Link, useNavigate } from "react-router-dom";

const Cart = () => {
  const { cartItems, updateQuantity, removeFromCart, clearCart, getCartTotal } = useContext(CartContext);
  const navigate = useNavigate();

  const total = getCartTotal();

  return (
    <div style={{ padding: "24px 10%" }}>
      <h2>Giỏ hàng của bạn</h2>
      {cartItems.length === 0 ? (
        <div>
          <p>Giỏ hàng trống.</p>
          <Link to="/product">Tiếp tục mua sắm</Link>
        </div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "2fr 300px", gap: 20 }}>
          <div>
            {cartItems.map(item => (
              <div key={item.product._id || item.id} style={{ display: "flex", gap: 12, padding: 12, borderBottom: "1px solid #eee" }}>
                <img src={item.product.image || item.product.images?.[0] || "/placeholder.png"} alt={item.product.name} style={{ width: 96, height: 96, objectFit: "cover" }} />
                <div style={{ flex: 1 }}>
                  <h4>{item.product.name}</h4>
                  <div>{(item.product.price || 0).toLocaleString()}₫</div>
                  <div style={{ marginTop: 8 }}>
                    <button onClick={() => updateQuantity(item.product._id, item.quantity - 1)}>-</button>
                    <span style={{ margin: "0 8px" }}>{item.quantity}</span>
                    <button onClick={() => updateQuantity(item.product._id, item.quantity + 1)}>+</button>
                    <button onClick={() => removeFromCart(item.product._id)} style={{ marginLeft: 12 }}>Xóa</button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <aside style={{ background: "#fff", padding: 16, borderRadius: 8 }}>
            <h4>Tổng tiền</h4>
            <div style={{ fontSize: 20, fontWeight: 700 }}>{total.toLocaleString()}₫</div>
            <button className="btn" style={{ marginTop: 12 }} onClick={() => navigate("/checkout")}>Thanh toán</button>
            <button onClick={clearCart} style={{ marginTop: 8 }} className="btn-outline">Xóa giỏ hàng</button>
          </aside>
        </div>
      )}
    </div>
  );
};

export default Cart;
